const express = require('express');
const crypto = require('crypto');
const app = express();

// Load secret from environment or AWS Secrets Manager
const ORIGIN_VERIFY_SECRET = process.env.ORIGIN_VERIFY_SECRET;
const CLOUDFRONT_DISTRIBUTION_ID = process.env.CLOUDFRONT_DISTRIBUTION_ID;
const ALLOWED_CLOUDFRONT_IPS = [
  '13.32.0.0/15',
  '13.35.0.0/16',
  '52.84.0.0/15',
  '64.252.64.0/18',
  '99.84.0.0/16',
  '204.246.164.0/22',
  '205.251.192.0/19'
];

// Utility: Check if IP is in CIDR range
function isIPInCIDR(ip, cidr) {
  const [range, bits] = cidr.split('/');
  const mask = ~(2 ** (32 - parseInt(bits)) - 1);
  const ipNum = ip.split('.').reduce((int, oct) => (int << 8) + parseInt(oct), 0) >>> 0;
  const rangeNum = range.split('.').reduce((int, oct) => (int << 8) + parseInt(oct), 0) >>> 0;
  return (ipNum & mask) === (rangeNum & mask);
}

// Middleware: Validate CloudFront Origin Headers
function validateCloudFrontOrigin(req, res, next) {
  const originVerify = req.get('X-Origin-Verify');
  const distributionId = req.get('X-CloudFront-Distribution-ID');
  const clientIP = req.get('X-Forwarded-For')?.split(',')[0] || req.ip;

  // Log validation attempt
  console.log(`Origin validation: IP=${clientIP}, Header=${originVerify ? 'Present' : 'Missing'}`);

  // Check 1: Custom origin verification header
  if (!originVerify || originVerify !== ORIGIN_VERIFY_SECRET) {
    console.warn(`❌ Invalid or missing X-Origin-Verify header from ${clientIP}`);
    return res.status(403).json({
      error: 'Forbidden',
      message: 'Direct origin access is not permitted'
    });
  }

  // Check 2: CloudFront distribution ID
  if (!distributionId || distributionId !== CLOUDFRONT_DISTRIBUTION_ID) {
    console.warn(`❌ Invalid CloudFront distribution ID from ${clientIP}`);
    return res.status(403).json({
      error: 'Forbidden',
      message: 'Invalid distribution source'
    });
  }

  // Check 3: Verify source IP is from CloudFront (defense in depth)
  const isCloudFrontIP = ALLOWED_CLOUDFRONT_IPS.some(cidr => isIPInCIDR(clientIP, cidr));
  if (!isCloudFrontIP) {
    console.warn(`❌ Request from non-CloudFront IP: ${clientIP}`);
    return res.status(403).json({
      error: 'Forbidden',
      message: 'Invalid source network'
    });
  }

  // Check 4: Validate CloudFront viewer headers (optional anti-spoofing)
  const cloudFrontViewer = req.get('CloudFront-Is-Desktop-Viewer') || 
                          req.get('CloudFront-Is-Mobile-Viewer') || 
                          req.get('CloudFront-Is-SmartTV-Viewer') || 
                          req.get('CloudFront-Is-Tablet-Viewer');

  if (!cloudFrontViewer) {
    console.warn(`⚠️ Missing CloudFront viewer headers from ${clientIP}`);
    // Don't block, but log for monitoring
  }

  console.log(`✅ Valid CloudFront request from ${clientIP}`);
  next();
}

// Apply middleware globally to all routes
app.use(validateCloudFrontOrigin);

// Health check endpoint (bypasses validation for ALB health checks)
app.get('/health', (req, res) => {
  res.status(200).json({ status: 'healthy' });
});

// Protected application routes
app.get('/api/data', (req, res) => {
  res.json({ message: 'This endpoint is protected by CloudFront' });
});

// Error handler for validation failures
app.use((err, req, res, next) => {
  console.error('Application error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

// Start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`🚀 Origin server running on port ${PORT}`);
  console.log(`🔒 CloudFront origin validation enabled`);
  console.log(`📋 Distribution ID: ${CLOUDFRONT_DISTRIBUTION_ID}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});
